def fetch(timeout_s, cost_s):
    if cost_s > timeout_s:
        raise TimeoutError("timeout")
    return "ok"

print(fetch(1.0, 0.5))
try:
    print(fetch(0.1, 1.0))
except TimeoutError:
    print("timeout")

api = {
    1: {"items": ["a"], "next": 2},
    2: {"items": ["b", "c"], "next": None},
}

def collect_all(api):
    out = []
    page = 1
    while page is not None:
        chunk = api[page]
        out.extend(chunk["items"])
        page = chunk["next"]
    return out

print(collect_all(api))

def should_retry(status):
    return status in {429, 503}

for s in [400, 404, 429, 503, 200]:
    print(s, should_retry(s))

def require_token(env):
    tok = env.get("API_TOKEN")
    if not tok:
        raise ValueError("API_TOKEN missing")
    return tok

print(require_token({"API_TOKEN": "abc"}))
try:
    require_token({})
except ValueError as e:
    print(e)

class Cache:
    def __init__(self):
        self._d = {}
    def get(self, url):
        if url in self._d:
            return self._d[url], True
        return None, False
    def set(self, url, body):
        self._d[url] = body

c = Cache()
c.set("http://x", {"ok": 1})
print(c.get("http://x"))
print(c.get("http://y"))

def min_provenance(url, status, cache_hit):
    return {
        "source_url": url,
        "fetched_at": "2026-07-20T00:00:00Z",
        "status_code": status,
        "cache_hit": cache_hit,
    }

print(min_provenance("http://api/x", 200, False))

def assert_keys(payload, required):
    missing = sorted(set(required) - set(payload))
    if missing:
        raise AssertionError(f"missing {missing}")
    return "ok"

print(assert_keys({"id": 1, "region": "L"}, ["id", "region"]))
try:
    assert_keys({"id": 1}, ["id", "region"])
except AssertionError as e:
    print(e)

def fetch_with_fallback(status, local_body):
    if status >= 500:
        return (local_body, "offline")
    if status == 200:
        return ({"online": True}, "online")
    return (local_body, "offline")

print(fetch_with_fallback(200, {}))
print(fetch_with_fallback(503, {"local": 1}))

