ALLOWED = {"address", "city", "country"}

def allowed_for_public_geocoder(payload):
    return set(payload) <= ALLOWED

print(allowed_for_public_geocoder({"city": "Lima", "country": "PE"}))
print(allowed_for_public_geocoder({"document_id": "DNI1", "city": "Lima"}))

def valid_lat_lon(lat, lon):
    return -90 <= lat <= 90 and -180 <= lon <= 180

for pair in [(0, 0), (91, 0), (0, 181), (-12.04, -77.04)]:
    print(valid_lat_lon(*pair))

